mapper.sql:
FROM ELIB_COMMENT a JOIN ELIB_BOOK b ON a.book_idx = b.book_idx JOIN ELIB_MEMBER c ON a.member_id = c.member_id WHERE 1=1 AND a.book_idx = b.book_idx
AND b.type = #{type}
AND a.member_id LIKE '%'||#{member_id}||'%'
AND b.parent_id = #{parent_id}
AND b.cate_id = #{cate_id}
AND TO_DATE(#{search_sdt}, 'yyyy-mm-dd') <= a.regdt
AND a.regdt <= TO_DATE(#{search_edt} || ' 23:59:59', 'yyyy-mm-dd hh24:mi:ss')

mapper.select:
${pagingTop}
SELECT
	comment_idx, TO_CHAR(regdt, 'YYYY-MM-DD') AS regdt, book_idx, member_id, user_comment

${pagingBottom}

mapper.insert:
INSERT INTO ELIB_COMMENT (
	comment_idx, regdt, book_idx, member_id, user_comment
) VALUES (
	ELIB_COMMENT_SEQ.NEXTVAL, SYSDATE, #{book_idx}, #{member_id}, #{user_comment}
)

mapper.update:
UPDATE ELIB_COMMENT SET
	user_comment = #{user_comment}
WHERE
	comment_idx = #{comment_idx}
